<script>
(function() {
  'use strict';

  // ── Clock ─────────────────────────────────────────────────────────────────
  function updateClock() {
    const now = new Date();
    document.getElementById('clock').textContent =
      now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  }
  updateClock();
  setInterval(updateClock, 5000);

  // ── Window management ─────────────────────────────────────────────────────
  function bringToFront(win) {
    document.querySelectorAll('.win').forEach(w => w.classList.remove('active'));
    win.classList.add('active');
  }

  document.querySelectorAll('.win').forEach(win => {
    win.addEventListener('mousedown', () => bringToFront(win));
  });

  // Close buttons
  document.querySelectorAll('.win-close').forEach(btn => {
    btn.addEventListener('click', (e) => {
      e.stopPropagation();
      const target = btn.dataset.target;
      document.getElementById(target).classList.add('hidden');
    });
  });

  // Dragging
  function makeDraggable(win, titlebar) {
    let dragging = false, ox = 0, oy = 0;
    titlebar.addEventListener('mousedown', (e) => {
      if (e.target.classList.contains('win-ctrl')) return;
      dragging = true;
      const rect = win.getBoundingClientRect();
      ox = e.clientX - rect.left;
      oy = e.clientY - rect.top;
      bringToFront(win);
      e.preventDefault();
    });
    document.addEventListener('mousemove', (e) => {
      if (!dragging) return;
      const deskRect = document.getElementById('desktop').getBoundingClientRect();
      let nx = e.clientX - ox - deskRect.left;
      let ny = e.clientY - oy - deskRect.top;
      nx = Math.max(0, Math.min(nx, deskRect.width - win.offsetWidth));
      ny = Math.max(30, Math.min(ny, deskRect.height - win.offsetHeight));
      win.style.left = nx + 'px';
      win.style.top  = ny + 'px';
    });
    document.addEventListener('mouseup', () => { dragging = false; });
  }

  makeDraggable(
    document.getElementById('files-window'),
    document.getElementById('files-titlebar')
  );
  makeDraggable(
    document.getElementById('notepad-window'),
    document.getElementById('notepad-titlebar')
  );

  // Resizing
  function makeResizable(win, handle) {
    let resizing = false, sx = 0, sy = 0, sw = 0, sh = 0;
    handle.addEventListener('mousedown', (e) => {
      resizing = true;
      sx = e.clientX; sy = e.clientY;
      sw = win.offsetWidth; sh = win.offsetHeight;
      bringToFront(win);
      e.preventDefault();
      e.stopPropagation();
    });
    document.addEventListener('mousemove', (e) => {
      if (!resizing) return;
      const nw = Math.max(360, sw + (e.clientX - sx));
      const nh = Math.max(240, sh + (e.clientY - sy));
      win.style.width  = nw + 'px';
      win.style.height = nh + 'px';
    });
    document.addEventListener('mouseup', () => { resizing = false; });
  }

  makeResizable(
    document.getElementById('files-window'),
    document.getElementById('files-resize')
  );
  makeResizable(
    document.getElementById('notepad-window'),
    document.getElementById('notepad-resize')
  );

  // Launcher buttons
  document.getElementById('open-files').addEventListener('click', () => {
    const w = document.getElementById('files-window');
    w.classList.remove('hidden');
    bringToFront(w);
  });

  document.getElementById('open-notepad').addEventListener('click', () => {
    const w = document.getElementById('notepad-window');
    w.classList.remove('hidden');
    bringToFront(w);
    renderTabs();
    renderEditor();
  });

  // ── Filesystem ────────────────────────────────────────────────────────────
  const FS = {
