  function getIcon(name, type) {
    if (type === 'dir') return fileIcons.dir;
    const ext = name.split('.').pop().toLowerCase();
    return fileIcons[ext] || '&#128196;';
  }

  function normPath(p) {
    if (p !== '/' && p.endsWith('/')) p = p.slice(0, -1);
    return p;
  }

  let currentPath = '/';

  function navigateTo(path) {
    path = normPath(path);
    const node = FS[path];
    if (!node || node.type !== 'dir') return;
    currentPath = path;
    renderFiles();
  }

  function renderFiles() {
    const listing = document.getElementById('files-listing');
    const pathEl  = document.getElementById('files-path');
    const statusEl = document.getElementById('files-status');
    const upBtn   = document.getElementById('files-up');

    pathEl.textContent = currentPath;
    upBtn.disabled = (currentPath === '/');

    const node = FS[currentPath];
    listing.innerHTML = '';

    if (!node || !node.children || node.children.length === 0) {
      statusEl.textContent = '0 items';
      return;
    }

    const children = node.children;
    statusEl.textContent = children.length + ' item' + (children.length !== 1 ? 's' : '');

    children.forEach(name => {
      const fullPath = (currentPath === '/' ? '' : currentPath) + '/' + name;
      const child = FS[fullPath];
      const type = (child && child.type === 'dir') ? 'dir' : 'file';

      const el = document.createElement('div');
      el.className = 'fs-item';
      el.dataset.name = name;
      el.dataset.path = fullPath;
      el.dataset.type = type;

      const iconEl = document.createElement('div');
      iconEl.className = 'fs-icon';
      iconEl.innerHTML = getIcon(name, type);

      const nameEl = document.createElement('div');
      nameEl.className = 'fs-name';
      nameEl.textContent = name;

      el.appendChild(iconEl);
      el.appendChild(nameEl);
      listing.appendChild(el);

      el.addEventListener('click', () => {
        document.querySelectorAll('.fs-item').forEach(i => i.classList.remove('selected'));
        el.classList.add('selected');
      });

      el.addEventListener('dblclick', () => {
        if (type === 'dir') {
          navigateTo(fullPath);
        }
      });
    });
  }

  document.getElementById('files-up').addEventListener('click', () => {
    if (currentPath === '/') return;
    const parts = currentPath.split('/').filter(Boolean);
    parts.pop();
    const parent = parts.length === 0 ? '/' : '/' + parts.join('/');
    navigateTo(parent);
  });

  // Init files
  renderFiles();

  // ── Notepad ───────────────────────────────────────────────────────────────
  const STORAGE_KEY = 'desktop_notepad_v1';

  function loadNotepadState() {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (raw) return JSON.parse(raw);
    } catch(e) {}
    return { tabs: [{ id: 1, title: 'Note 1', content: '' }], activeId: 1, nextId: 2 };
  }

  function saveNotepadState() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(notepadState));
    } catch(e) {}
  }

  let notepadState = loadNotepadState();

  function getActiveTab() {
    return notepadState.tabs.find(t => t.id === notepadState.activeId) || notepadState.tabs[0];
  }

  function renderTabs() {
    const tabsEl = document.getElementById('tabs');
    tabsEl.innerHTML = '';
    notepadState.tabs.forEach(tab => {
      const el = document.createElement('div');
      el.className = 'tab' + (tab.id === notepadState.activeId ? ' active' : '');
      el.dataset.id = tab.id;

      const titleSpan = document.createElement('span');
      titleSpan.textContent = tab.title;

      const closeBtn = document.createElement('button');
      closeBtn.className = 'tab-close';
      closeBtn.innerHTML = '&#215;';
      closeBtn.title = 'Close tab';
      closeBtn.addEventListener('click', (e) => {
        e.stopPropagation();
        closeTab(tab.id);
      });

      el.appendChild(titleSpan);
      el.appendChild(closeBtn);
      tabsEl.appendChild(el);

      el.addEventListener('click', () => {
        notepadState.activeId = tab.id;
        saveNotepadState();
        renderTabs();
        renderEditor();
      });
    });
  }

  function renderEditor() {
    const editor = document.getElementById('editor');
    const active = getActiveTab();
    if (active) {
      editor.value = active.content || '';
    } else {
      editor.value = '';
    }
    updateEditorStatus();
  }

  function updateEditorStatus() {
    const val = document.getElementById('editor').value;
    document.getElementById('np-chars').textContent = val.length + ' chars';
    const lines = val === '' ? 1 : val.split('\n').length;
    document.getElementById('np-lines').textContent = lines + ' line' + (lines !== 1 ? 's' : '');
  }

  function closeTab(id) {
    if (notepadState.tabs.length === 1) {
      notepadState.tabs[0].content = '';
      notepadState.tabs[0].title = 'Note 1';
      notepadState.activeId = notepadState.tabs[0].id;
      saveNotepadState();
      renderTabs();
      renderEditor();
      return;
    }
    const idx = notepadState.tabs.findIndex(t => t.id === id);
    notepadState.tabs.splice(idx, 1);
    if (notepadState.activeId === id) {
      const newIdx = Math.max(0, idx - 1);
      notepadState.activeId = notepadState.tabs[newIdx].id;
    }
    saveNotepadState();
    renderTabs();
    renderEditor();
  }

  document.getElementById('new-tab').addEventListener('click', () => {
    const id = notepadState.nextId++;
    const title = 'Note ' + id;
    notepadState.tabs.push({ id, title, content: '' });
    notepadState.activeId = id;
    saveNotepadState();
    renderTabs();
    renderEditor();
  });

  document.getElementById('editor').addEventListener('input', (e) => {
    const active = getActiveTab();
    if (active) {
      active.content = e.target.value;
      saveNotepadState();
    }
    updateEditorStatus();
  });

  // Init notepad
  renderTabs();
  renderEditor();
})();
</script>
